"use strict";(self.webpackChunksysanalyst_kb=self.webpackChunksysanalyst_kb||[]).push([["64641"],{12763(e){e.exports=JSON.parse('{"tag":{"label":"socnet","permalink":"/sysanalyst-kb.github.io/docs/tags/socnet","allTagsPath":"/sysanalyst-kb.github.io/docs/tags","count":8,"items":[{"id":"specialization/socnet-feed","title":"\u041B\u0435\u043D\u0442\u0430 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430 \u2014 feed, ranking, \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0430\u0446\u0438\u0438","description":"\u041B\u0435\u043D\u0442\u0430 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430 (feed) \u2014 \u043E\u0441\u043D\u043E\u0432\u043D\u043E\u0439 \u0438\u043D\u0442\u0435\u0440\u0444\u0435\u0439\u0441 \u043B\u044E\u0431\u043E\u0439 \u0441\u043E\u0446\u0441\u0435\u0442\u0438. \u042D\u0442\u043E \u043D\u0435 \u0441\u043B\u0443\u0447\u0430\u0439\u043D\u044B\u0439 \u0441\u043F\u0438\u0441\u043E\u043A \u043F\u043E\u0441\u0442\u043E\u0432, \u0430 \u0441\u043B\u043E\u0436\u043D\u0430\u044F ML-\u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0440\u0430\u043D\u0436\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0440\u0435\u0448\u0430\u0435\u0442: \u0447\u0442\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u0442\u044C \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044E, \u0432 \u043A\u0430\u043A\u043E\u043C \u043F\u043E\u0440\u044F\u0434\u043A\u0435, \u0441\u043A\u043E\u043B\u044C\u043A\u043E \u0440\u0435\u043A\u043B\u0430\u043C\u044B, \u043A\u0430\u043A \u0447\u0430\u0441\u0442\u043E \u043E\u0431\u043D\u043E\u0432\u043B\u044F\u0442\u044C. \u0410\u043B\u0433\u043E\u0440\u0438\u0442\u043C\u0438\u0447\u0435\u0441\u043A\u0430\u044F \u043B\u0435\u043D\u0442\u0430 (TikTok FYP, YouTube Recommendations) \u2014 \u043A\u043B\u044E\u0447\u0435\u0432\u043E\u0435 \u043A\u043E\u043D\u043A\u0443\u0440\u0435\u043D\u0442\u043D\u043E\u0435 \u043F\u0440\u0435\u0438\u043C\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0442\u0438\u043F\u044B \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430, \u0441\u0438\u0433\u043D\u0430\u043B\u044B \u0440\u0430\u043D\u0436\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F, A/B \u0442\u0435\u0441\u0442\u044B \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 \u043B\u0435\u043D\u0442\u044B (CTR, watch time, diversity).","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-feed"},{"id":"specialization/socnet-messenger","title":"\u041C\u0435\u0441\u0441\u0435\u043D\u0434\u0436\u0435\u0440\u044B \u0438 real-time \u043A\u043E\u043C\u043C\u0443\u043D\u0438\u043A\u0430\u0446\u0438\u0438","description":"\u041C\u0435\u0441\u0441\u0435\u043D\u0434\u0436\u0435\u0440 \u2014 real-time \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u043E\u0431\u043C\u0435\u043D\u0430 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u044F\u043C\u0438, \u043E\u0434\u043D\u0430 \u0438\u0437 \u0441\u0430\u043C\u044B\u0445 \u0441\u043B\u043E\u0436\u043D\u044B\u0445 \u0438\u043D\u0444\u0440\u0430\u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u043D\u044B\u0445 \u0437\u0430\u0434\u0430\u0447 \u0432 IT. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B: \u0442\u0440\u0430\u043D\u0441\u043F\u043E\u0440\u0442 (WebSocket, MQTT, HTTP Polling), \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u0435 (key-value + SQL \u0434\u043B\u044F \u0438\u0441\u0442\u043E\u0440\u0438\u0438), \u043C\u0430\u0440\u0448\u0440\u0443\u0442\u0438\u0437\u0430\u0446\u0438\u044F (Inbox/Outbox \u043C\u043E\u0434\u0435\u043B\u044C), E2EE (Signal Protocol), \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0430 (offline queue + push-\u0443\u0432\u0435\u0434\u043E\u043C\u043B\u0435\u043D\u0438\u044F), \u0433\u0440\u0443\u043F\u043F\u043E\u0432\u044B\u0435 \u0447\u0430\u0442\u044B \u0438 \u0438\u043D\u0442\u0435\u0433\u0440\u0430\u0446\u0438\u0438 (bots, payments). \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0442\u0438\u043F\u044B \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439, \u0441\u0442\u0430\u0442\u0443\u0441\u043D\u0443\u044E \u043C\u043E\u0434\u0435\u043B\u044C, \u0441\u0445\u0435\u043C\u0443 \u0445\u0440\u0430\u043D\u0435\u043D\u0438\u044F, E2EE-\u0430\u0440\u0445\u0438\u0442\u0435\u043A\u0442\u0443\u0440\u0443 \u0438 \u0441\u0438\u0441\u0442\u0435\u043C\u0443 \u0434\u043E\u0441\u0442\u0430\u0432\u043A\u0438 \u0434\u043B\u044F \u043C\u0438\u043B\u043B\u0438\u0430\u0440\u0434\u043E\u0432 \u0441\u043E\u043E\u0431\u0449\u0435\u043D\u0438\u0439 \u0432 \u0434\u0435\u043D\u044C.","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-messenger"},{"id":"specialization/socnet-moderation","title":"\u041C\u043E\u0434\u0435\u0440\u0430\u0446\u0438\u044F \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430 \u0438 \u0431\u0435\u0437\u043E\u043F\u0430\u0441\u043D\u043E\u0441\u0442\u044C","description":"\u041C\u043E\u0434\u0435\u0440\u0430\u0446\u0438\u044F \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430 \u2014 \u0441\u0438\u0441\u0442\u0435\u043C\u0430 \u0444\u0438\u043B\u044C\u0442\u0440\u0430\u0446\u0438\u0438 \u0437\u0430\u043F\u0440\u0435\u0449\u0451\u043D\u043D\u043E\u0433\u043E \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430 (ASR \u0442\u0438\u043F\u044B \u043D\u0430\u0440\u0443\u0448\u0435\u043D\u0438\u0439, \u043F\u0440\u0430\u0432\u0438\u043B\u0430 \u043C\u043E\u0434\u0435\u0440\u0430\u0446\u0438\u0438, \u0441\u0438\u0441\u0442\u0435\u043C\u044B \u0436\u0430\u043B\u043E\u0431, \u0430\u043F\u0435\u043B\u043B\u044F\u0446\u0438\u0438, \u043C\u0435\u0442\u0440\u0438\u043A\u0438 (precision/recall, time to action, appeal rate) \u0438 \u0442\u0440\u0435\u0431\u043E\u0432\u0430\u043D\u0438\u044F \u043A AI-\u043C\u043E\u0434\u0435\u0440\u0430\u0442\u043E\u0440\u0430\u043C. \u0420\u0435\u0433\u0443\u043B\u044F\u0442\u043E\u0440\u043D\u043E\u0435 \u0434\u0430\u0432\u043B\u0435\u043D\u0438\u0435 (DSA, COPPA, \u0420\u041A\u041D) \u0434\u0435\u043B\u0430\u0435\u0442 \u043C\u043E\u0434\u0435\u0440\u0430\u0446\u0438\u044E \u043F\u0435\u0440\u0432\u044B\u043C \u043A\u043B\u0430\u0441\u0441\u043E\u043C \u0440\u0438\u0441\u043A\u0430.","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-moderation"},{"id":"specialization/socnet-monetization","title":"\u041C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u044F \u0441\u043E\u0446\u0441\u0435\u0442\u0435\u0439 \u2014 \u0440\u0435\u043A\u043B\u0430\u043C\u0430, \u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0438, creator economy","description":"\u041C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u044F \u0441\u043E\u0446\u0441\u0435\u0442\u0435\u0439 $500B+ digital ads (2025), $100B+ creator economy. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0430\u0443\u043A\u0446\u0438\u043E\u043D \u0440\u0435\u043A\u043B\u0430\u043C\u044B, \u043C\u043E\u0434\u0435\u043B\u0438 \u043E\u043F\u043B\u0430\u0442\u044B, creator payouts \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 (ARPU, fill rate, eCPM, LTV/CAC).","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-monetization"},{"id":"specialization/socnet-platform","title":"\u041F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430 \u2014 \u0432\u0438\u0434\u0435\u043E, \u043C\u0443\u0437\u044B\u043A\u0430, stories, live","description":"\u041A\u043E\u043D\u0442\u0435\u043D\u0442-\u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0430 \u2014 \u0432\u0438\u0434\u0435\u043E\u0445\u043E\u0441\u0442\u0438\u043D\u0433 (short/long), \u043C\u0443\u0437\u044B\u043A\u0430, stories, live-\u0441\u0442\u0440\u0438\u043C\u044B, \u043F\u043E\u0434\u043A\u0430\u0441\u0442\u044B. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043A\u043E\u043C\u043F\u043E\u043D\u0435\u043D\u0442\u044B CloudFront, Cloudflare, Akamai), DRM (Widevine, FairPlay), \u0437\u0430\u0433\u0440\u0443\u0437\u043A\u0430, \u0441\u0442\u0440\u0438\u043C\u0438\u043D\u0433 (HLS/DASH/LL-HLS), \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0430\u0446\u0438\u0438. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0444\u043E\u0440\u043C\u0430\u0442\u044B \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u0430, workflow \u0437\u0430\u0433\u0440\u0443\u0437\u043A\u0438, ABR ladder, \u0431\u0430\u043B\u0430\u043D\u0441 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430/\u0441\u043A\u043E\u0440\u043E\u0441\u0442\u0438 \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 (startup time, buffering rate, VMAF). YouTube: 720K \u0447\u0430\u0441\u043E\u0432/\u0434\u0435\u043D\u044C, \u0442\u044B\u0441\u044F\u0447\u0438 edge-\u0441\u0435\u0440\u0432\u0435\u0440\u043E\u0432, \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F CDN (Google Global Cache).","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-platform"},{"id":"specialization/socnet-eco","title":"\u041F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0435\u043D\u043D\u044B\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0438 \u2014 API, SDK, \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0439","description":"\u041F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u0435\u043D\u043D\u044B\u0435 \u043C\u0435\u0445\u0430\u043D\u0438\u043A\u0438 \u2014 Public API \u0438 SDK \u0434\u043B\u044F \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432, \u043C\u0430\u0440\u043A\u0435\u0442\u043F\u043B\u0435\u0439\u0441 \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0439 (\u0431\u043E\u0442\u044B, \u043C\u0438\u043D\u0438-\u0430\u043F\u043F\u044B, \u0438\u0433\u0440\u044B \u0432\u043D\u0443\u0442\u0440\u0438 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B) \u0438 creator economy (\u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u044B \u0434\u043B\u044F \u0430\u0432\u0442\u043E\u0440\u043E\u0432). \u041F\u0440\u0438\u043C\u0435\u0440\u044B: Telegram Bot API (10M+ \u0431\u043E\u0442\u043E\u0432), WeChat Mini Programs (5M+ \u043F\u0440\u0438\u043B\u043E\u0436\u0435\u043D\u0438\u0439), Discord API (1M+ \u0431\u043E\u0442\u043E\u0432), Facebook Graph API. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 API-\u043A\u043E\u043D\u0442\u0440\u0430\u043A\u0442\u044B, SDK, revenue share (70/30), \u043F\u043E\u043B\u0438\u0442\u0438\u043A\u0443 \u043F\u0443\u0431\u043B\u0438\u043A\u0430\u0446\u0438\u0438, rate limiting \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u044D\u043A\u043E\u0441\u0438\u0441\u0442\u0435\u043C\u044B (developer NPS, app quality, ecosystem revenue).","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-eco"},{"id":"specialization/socnet-graph","title":"\u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0439 \u0433\u0440\u0430\u0444 \u0438 \u0434\u0440\u0443\u0437\u044C\u044F","description":"\u0421\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u0439 \u0433\u0440\u0430\u0444 \u2014 \u0441\u0442\u0440\u0443\u043A\u0442\u0443\u0440\u0430 \u0441\u0432\u044F\u0437\u0435\u0439 \u043C\u0435\u0436\u0434\u0443 \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u044F\u043C\u0438 (\u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0438, \u0434\u0440\u0443\u0437\u044C\u044F, \u0444\u043E\u043B\u043B\u043E\u0432\u0435\u0440\u044B, \u0431\u043B\u043E\u043A\u0438, \u043C\u044C\u044E\u0442\u044B). \u0425\u0440\u0430\u043D\u0438\u0442\u0441\u044F \u0432 \u0433\u0440\u0430\u0444\u043E\u0432\u044B\u0445 \u0411\u0414 (Neo4j, DGraph) \u0438\u043B\u0438 key-value (Redis, Cassandra). \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u043E\u043F\u0435\u0440\u0430\u0446\u0438\u0438 Facebook \u0445\u0440\u0430\u043D\u0438\u0442 250B+ edges, LinkedIn \u2014 80B, \u043E\u0431\u0440\u0430\u0431\u0430\u0442\u044B\u0432\u0430\u044E\u0442 10M+ \u0437\u0430\u043F\u0440\u043E\u0441\u043E\u0432/\u0441\u0435\u043A. \u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u043F\u0440\u043E\u0435\u043A\u0442\u0438\u0440\u0443\u0435\u0442 \u0442\u0438\u043F\u044B \u0441\u0432\u044F\u0437\u0435\u0439, \u0430\u043B\u0433\u043E\u0440\u0438\u0442\u043C\u044B \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0430\u0446\u0438\u0439 \u0434\u0440\u0443\u0437\u0435\u0439 (friend-of-friend, ML-embeddings) \u0438 \u043C\u0435\u0442\u0440\u0438\u043A\u0438 \u0433\u0440\u0430\u0444\u0430 (density, clustering coefficient, PageRank).","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-graph"},{"id":"specialization/socnet-path","title":"\u0421\u043E\u0446\u0441\u0435\u0442\u0438 \u0438 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u043D\u044B\u0435 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u044B \u2014 \u0440\u043E\u043B\u044C, \u0441\u043F\u0435\u0446\u0438\u0444\u0438\u043A\u0430, \u043F\u0443\u0442\u044C","description":"\u0410\u043D\u0430\u043B\u0438\u0442\u0438\u043A \u0441\u043E\u0446\u0441\u0435\u0442\u0435\u0439 \u0438 \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u043D\u044B\u0445 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u0441 \u043B\u0435\u043D\u0442\u043E\u0439 (feed), \u043C\u0435\u0441\u0441\u0435\u043D\u0434\u0436\u0435\u0440\u0430\u043C\u0438, \u043C\u043E\u0434\u0435\u0440\u0430\u0446\u0438\u0435\u0439, \u0441\u043E\u0446\u0438\u0430\u043B\u044C\u043D\u044B\u043C \u0433\u0440\u0430\u0444\u043E\u043C, \u043C\u043E\u043D\u0435\u0442\u0438\u0437\u0430\u0446\u0438\u0435\u0439 (\u0440\u0435\u043A\u043B\u0430\u043C\u0430/\u043F\u043E\u0434\u043F\u0438\u0441\u043A\u0438), \u043A\u043E\u043D\u0442\u0435\u043D\u0442\u043D\u043E\u0439 \u043F\u043B\u0430\u0442\u0444\u043E\u0440\u043C\u043E\u0439 (\u0432\u0438\u0434\u0435\u043E, \u043C\u0443\u0437\u044B\u043A\u0430, stories) \u0438 API/SDK \u0434\u043B\u044F \u0432\u043D\u0435\u0448\u043D\u0438\u0445 \u0440\u0430\u0437\u0440\u0430\u0431\u043E\u0442\u0447\u0438\u043A\u043E\u0432. \u041A\u043B\u044E\u0447\u0435\u0432\u044B\u0435 \u0432\u044B\u0437\u043E\u0432\u044B \u2014 \u043C\u0430\u0441\u0448\u0442\u0430\u0431 (\u043C\u0438\u043B\u043B\u0438\u0430\u0440\u0434\u044B \u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u0439), real-time, AI-\u043C\u043E\u0434\u0435\u0440\u0430\u0446\u0438\u044F (ASR/NSFW), \u0440\u0435\u043A\u043E\u043C\u0435\u043D\u0434\u0430\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u0441\u0438\u0441\u0442\u0435\u043C\u044B. \u0418\u043D\u0434\u0443\u0441\u0442\u0440\u0438\u044F \u043C\u0435\u043D\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u0436\u0434\u044B\u0435 2-3 \u0433\u043E\u0434\u0430: TikTok \u043F\u0435\u0440\u0435\u0432\u0435\u0440\u043D\u0443\u043B feed, Clubhouse \u2014 \u0430\u0443\u0434\u0438\u043E, Threads \u2014 \u043C\u0438\u043A\u0440\u043E\u0431\u043B\u043E\u0433\u0438\u043D\u0433.","permalink":"/sysanalyst-kb.github.io/docs/specialization/socnet-path"}],"unlisted":false}}')}}]);